    async componentDidMount() {
        RouteGuard('MenteeProfile');
        this.profileStatusUpdate()
        // Get Session data
        if (userSession) {
            this.setState(prevState => ({
                personalInfo: {
                    ...prevState.personalInfo,
                    first_name: userSession.__userDetail.first_name,
                    last_name: userSession.__userDetail.last_name,
                    email: userSession.__userDetail.email,
                }

            }))
        }

        // Get Countries
        const getCountries = await ApiRequest.getRequest('/getCountries');
        if (getCountries && getCountries.data.countries && getCountries.status === 200) {
            this.setState({
                countries: getCountries.data.countries
            })
        }

        // Get Personal Information
        const getPersonalInfo = await ApiRequest.getRequest('/getPersonalInformation')
        if (getPersonalInfo && getPersonalInfo.data.personalInfo[0] !== undefined && getPersonalInfo.status === 200) {
            let personalInfo = getPersonalInfo.data.personalInfo[0];
            const cities = await ApiRequest.getRequest(`/getCountryCities/${personalInfo.country.id}`);
            if (personalInfo) {
                this.setState({
                    getPersonalInfo: personalInfo
                })
                this.setState(prevState => ({
                    personalInfo: {
                        ...prevState.personalInfo,
                        first_name: personalInfo.first_name,
                        last_name: personalInfo.last_name,
                        email: personalInfo.email,
                        country: personalInfo.country.id,
                        city: personalInfo.city.id,
                        cityOption: {
                            value: personalInfo.city.id,
                            label: personalInfo.city.name
                        },
                        countryOption: {
                            value: personalInfo.country.id,
                            label: personalInfo.country.name
                        },
                        cities: cities.data.cities ? cities.data.cities : []
                    }

                }))
            }
        }
        // End Personal Information

        // Get Skills Details
        const getSkills = await ApiRequest.getRequest('/getSkill');
        if (getSkills && getSkills.status === 200) {
            this.makeSkillsArray(getSkills.data.skills);
            let skillsHtml = this.insertedCardDetail(getSkills);
            this.skillStrengthBar(1);
            if (skillsHtml !== undefined) {
                this.setState({
                    appendCard: skillsHtml
                })
            }
        }
        // End Skill Details

        // Work Experience
        const getWorkExperience = await ApiRequest.getRequest('/getworkexperience');
        if (getWorkExperience && getWorkExperience.status === 200) {
            this.makeWorkExpArray(getWorkExperience.data.WorkExperience);
            let workExpHtml = this.insertedExpCardDetail(getWorkExperience);
            if (workExpHtml !== undefined) {
                this.setState(prevState => ({
                    workExperience: {
                        ...prevState.workExperience,
                        cardHtml: workExpHtml
                    }
                }))
            }
        }

        // Education Work
        const getEducationD = await ApiRequest.getRequest('/geteducation');
        if (getEducationD && getEducationD.status === 200) {
            this.makeWorkEduArray(getEducationD.data.educationDetails);
            let eduHtml = this.insertedEduCardDetail(getEducationD);
            if (eduHtml !== undefined) {
                this.setState(prevState => ({
                    education: {
                        ...prevState.education,
                        cardHtml: eduHtml
                    }
                }))
            }
        }
    }

