    /**
     * Personal Information save in database and Validation
     */
    submitPersonalInfo() {
        const { first_name, last_name, email, country, city } = this.state.personalInfo;
        let { firstNameError, lastNameError, emailError, countryError, cityError } = '';
        if (!first_name) {
            firstNameError = "This field is required";
        }
        if (!last_name) {
            lastNameError = "This field is required";
        }
        if (!email) {
            emailError = "This field is required";
        }
        if (!country) {
            countryError = "This field is required";
        }
        if (!city) {
            cityError = "This field is required";
        }
        this.setState(prevState => ({
            personalInfo: {
                ...prevState.personalInfo,
                error: {
                    ...prevState.personalInfo.error,
                    firstNameError: firstNameError,
                    lastNameError: lastNameError,
                    emailError: emailError,
                    countryError: countryError

                }
            }
        })
        )
        if (firstNameError || lastNameError || emailError || countryError) {
            return true;
        }
        this.setState({ loading: true });
        Axios.post(`/personalInformation`, { first_name, last_name, email, country, city }).then(response => {
            if (response.status === 200) {
                this.tabActiveByClassName('step_two');
                // toastAlert('success', 'Personal Information Successfully added')
            }
        }).catch(error => {
            toastAlert('error', 'Authentication Failed!')
        }).finally(() => {
            this.setState({ loading: false });
        });

    }

    // Skills Form Related Method

    /**
     * Help to make a skills array from already saved data
     * @param  {object} data
     */
    makeSkillsArray = (data) => {
        let skillsArr = this.state.skills.allSkills;
        data.map(el => {
            let arr = {
                skill: el.skill,
                strength: el.strength,
            }
            if (arr.skill && arr.strength) {
                if (skillsArr.length == 0) {
                    skillsArr.push(arr);
                } else {
                    let index = skillsArr.findIndex(x => x.skill == this.state.skills.skillName);
                    if (index === -1) {
                        skillsArr.push(arr);
                    } else {
                        skillsArr[index] = arr;
                    }
                }
            }
        })
        this.setState(prevState => ({
            ...prevState.skills,
            allSkills: skillsArr
        }))
    }

    /**
     * Skills form input change handling
     * @param  {object} event
     */
    onChangeSkill = (event) => {
        const { name, value } = event.target;
        const skills = ['skill_one', 'skill_two', 'skill_three', 'skill_four', 'skill_five'];
        var arr = {
            skillName: this.state.skills.skillName,
            skillStrength: this.state.skills.skillStrength
        }
        this.setState(prevState => ({
            skills: {
                ...prevState.skills,
                [name]: value
            }
        }), () => {
            if (name === 'skillStrength') {
                skills.forEach((el, val) => {
                    if (val < this.state.skills.skillStrength) {
                        this.setState({
                            [el]: true
                        })
                    } else {
                        this.setState({
                            [el]: false
                        })
                    }
                });
            }
        })
    }
    /**
     * Add skills card and Validation
     */
    addSkills() {
        // let arr = {};
        let skillsArr = this.state.skills.allSkills;
        let arr = {
            skill: this.state.skills.skillName,
            strength: this.state.skills.skillStrength
        }
        const { skillName, skillStrength } = this.state.skills;
        let { skillNameError, skillStrengthError } = '';
        // Validation
        if (!skillName) {
            skillNameError = "This field is required";
        }
        if (!skillStrength) {
            skillStrengthError = "This field is required";
        }
        this.setState(prevState => ({
            skills: {
                ...prevState.skills,
                error: {
                    ...prevState.skills.error,
                    skillNameError: skillNameError,
                    skillStrengthError: skillStrengthError

                }
            }
        })
        )
        if (skillStrengthError || skillNameError) {
            return true;
        }
        // End Validation

        // Added Skills to array 
        if (arr.skill && arr.strength) {
            if (skillsArr.length == 0) {
                skillsArr.push(arr);
            } else {
                let index = skillsArr.findIndex(x => x.skill == this.state.skills.skillName);
                if (index === -1) {
                    skillsArr.push(arr);
                } else {
                    skillsArr[index] = arr;
                }
            }
        }
        this.setState(prevState => ({
            ...prevState.skills,
            allSkills: skillsArr
        }))

        // Insert card
        let html = this.cardSkillsHtml();
        let prevHtml = this.state.appendCard;
        if (prevHtml.length == 0) {
            prevHtml.push(html);
        } else {
            let index = prevHtml.findIndex(x => x.key == this.state.skills.skillName);
            if (index === -1) {
                prevHtml.push(html);
            } else {
                prevHtml[index] = html;
            }
        }
        this.setState({
            appendCard: prevHtml
        })
        this.skillStrengthBar(1);
        // document.getElementById("append").appendChild(this.skillsHtml());

    }
