    /**
     * Delete Skill card 
     * @param  {object} event
     */
    deleteCard = (event) => {
        let prevHtml = this.state.appendCard;
        let skillsArr = this.state.skills.allSkills;
        let index = prevHtml.findIndex(x => x.key == event.currentTarget.getAttribute('data-name'));
        if (index !== -1) {
            prevHtml.splice(index, 1);
            this.setState({
                appendCard: prevHtml
            })
        }
        index = skillsArr.findIndex(x => x.skill == event.currentTarget.getAttribute('data-name'));
        if (index !== -1) {
            skillsArr.splice(index, 1);
            this.setState(prevState => ({
                ...prevState.skills,
                allSkills: skillsArr
            }))
        }
    }
    /**
     * Skill strength bar Maintainer 
     * @param  {number} data 
     */
    skillStrengthBar(data) {
        const skills = ['skill_one', 'skill_two', 'skill_three', 'skill_four', 'skill_five'];
        skills.forEach((el, val) => {
            if (val < data) {
                this.setState({
                    [el]: true
                })
            } else {
                this.setState({
                    [el]: false
                })
            }
        });

    }
    /**
     * User Saved skills detail used to create skills card
     * @param  {object} data
     */
    insertedCardDetail(data) {
        if (data.data.skills.length >= 1) {
            return data.data.skills.map(element => {
                this.skillStrengthBar(element.strength);
                return (
                    <div className="skill-card" className="col-md-6" key={element.skill}>
                        <div className="row mar-width-0 skillsWrap">

                            <h6>{element.skill}</h6>

                            <div className="squaredOne">
                                <input type="checkbox" value="None" id="skill_one" name="check"
                                    disabled checked={this.state.skill_one}
                                />
                                <label htmlFor="skill_one"></label>
                            </div>
                            <div className="squaredOne">
                                <input type="checkbox" value="None" id="skill_two" name="check" disabled checked={this.state.skill_two}

                                />
                                <label htmlFor="skill_two"></label>
                            </div>

                            <div className="squaredOne">
                                <input type="checkbox" value="None" id="skill_three" name="check" disabled checked={this.state.skill_three}

                                />
                                <label htmlFor="skill_three"></label>
                            </div>

                            <div className="squaredOne">
                                <input type="checkbox" value="None" id="skill_four" name="check" disabled checked={this.state.skill_four}

                                />
                                <label htmlFor="skill_four"></label>
                            </div>

                            <div className="squaredOne">
                                <input type="checkbox" value="None" id="skill_five" name="check" disabled checked={this.state.skill_five}
                                />
                                <label htmlFor="skill_five"></label>
                            </div>

                            <img src={trashImg} className="trash-img cursor-pointer" alt="" onClick={this.deleteCardFromDB} data-id={element.id} data-name={element.skill} />
                        </div>
                    </div>
                );
            });
        }
    }
    /**
     * Delete card from database 
     * @param  {object} event
     */
    deleteCardFromDB = async (event) => {
        this.deleteCard(event);
        let id = event.currentTarget.getAttribute('data-id');
        if (id) {
            const response = await ApiRequest.deleteRequest('/deleteskill/', id)
            if (response.data && response.data.status === 200) {
                toastAlert('success', 'Skill successfully deleted');
            }
        }
    }
    /**
     * Skill Details submitted to database 
     */
    submitSkills() {

        let skillsArr = this.state.skills.allSkills
        let stringArray = skillsArr.map(JSON.stringify);
        let uniqueStringArray = new Set(stringArray);


        skillsArr = Array.from(uniqueStringArray, JSON.parse);
        this.setState(prevState => ({
            ...prevState.skills,
            allSkills: skillsArr
        }), async () => {
            let skill = this.state.skills.allSkills;
            if (skill.length !== 0) {
                // let response = skillPostRequest('/skill',skill);
                const response = await ApiRequest.skillPostRequest('/skill', skill)
                if (response.status === 200) {
                    let html = this.insertedCardDetail(response);
                    this.tabActiveByClassName('step_three');
                    // toastAlert('success', 'Skills successfully added');
                    this.setState({
                        appendCard: html
                    })
                }
            } else {
                toastAlert('warn', 'Please add atleast one Skill then try');
            }


        })
    }
